import React from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

function RecipesPage() {
  return (
    <div className="app">
      <Navbar />

      <div
        style={{
          background: "red",
          color: "white",
          padding: "40px",
          fontSize: "40px",
          fontWeight: "bold"
        }}
      >
        TO JEST NOWY RECIPES PAGE TEST
      </div>

      <Footer />
    </div>
  );
}

export default RecipesPage;
